// playoffGenerator.js

function generatePlayoffs(clasificaciones) {
    const playoffs = {};

    for (const [liga, clasificacion] of Object.entries(clasificaciones)) {
        if (!clasificacion || clasificacion.length === 0) continue;

        const top5 = [...clasificacion]
            .sort((a, b) => b.puntos - a.puntos || (b.golesFavor - b.golesContra) - (a.golesFavor - a.golesContra))
            .slice(0, 5);

        if (liga === "Liga 2") {
            playoffs[liga] = generateLiga2Playoffs(top5);
        } else if (liga.includes("Primera RFEF")) {
            // Colectar grupos 1 y 2 para luego hacer cruces entre ellos
            const grupo = liga.includes("Grupo 1") ? "grupo1" : "grupo2";
            if (!playoffs["Primera RFEF"]) playoffs["Primera RFEF"] = { grupo1: [], grupo2: [] };
            playoffs["Primera RFEF"][grupo] = top5;
        } else if (liga.includes("Segunda RFEF")) {
            if (!playoffs[liga]) playoffs[liga] = generateRFEFPlayoffs(top5);
        } else if (liga.includes("Tercera RFEF")) {
            if (!playoffs["Tercera RFEF"]) playoffs["Tercera RFEF"] = { ronda1: [] };
            playoffs["Tercera RFEF"].ronda1.push(...generateRFEFPlayoffs(top5));
        }
    }

    // Combinar brackets de Primera RFEF si ambos están listos
    if (playoffs["Primera RFEF"]?.grupo1?.length === 5 && playoffs["Primera RFEF"]?.grupo2?.length === 5) {
        playoffs["Primera RFEF"] = generatePrimeraRFEFPlayoffs(
            playoffs["Primera RFEF"].grupo1,
            playoffs["Primera RFEF"].grupo2
        );
    }

    // Segunda ronda para Tercera RFEF (emparejamiento de los 18 ganadores de ronda 1)
    if (playoffs["Tercera RFEF"]?.ronda1.length === 9) {
        playoffs["Tercera RFEF"].ronda2 = generateTerceraFinales(playoffs["Tercera RFEF"].ronda1);
    }

    return playoffs;
}

// ------------------------ LIGA 2 ------------------------
function generateLiga2Playoffs([_, segundo, tercero, cuarto, quinto]) {
    return [
        [createMatch(segundo, quinto), createMatch(tercero, cuarto)], // Semis
        [] // Final (se completará luego)
    ];
}

// --------------------- PRIMERA RFEF ---------------------
function generatePrimeraRFEFPlayoffs(grupo1, grupo2) {
    return [
        [
            createMatch(grupo1[1], grupo2[4]),
            createMatch(grupo2[2], grupo1[3])
        ],
        [
            createMatch(grupo2[1], grupo1[4]),
            createMatch(grupo1[2], grupo2[3])
        ]
    ];
}

// ----------------- SEGUNDA / TERCERA RFEF -----------------
function generateRFEFPlayoffs(top5) {
    const [primero, segundo, tercero, cuarto, quinto] = top5;
    const pool = [
        [segundo, getRandomExcept([primero, segundo], [quinto])],
        [tercero, getRandomExcept([primero, tercero], [cuarto])]
    ];
    return pool.map(([a, b]) => createMatch(a, b));
}

// ------------ FINAL RONDA 2 DE TERCERA RFEF --------------
function generateTerceraFinales(bracketsGanadores) {
    const mezclados = shuffleArray(bracketsGanadores.map(pair => winnerMock(pair)));
    const finales = [];
    for (let i = 0; i < mezclados.length; i += 2) {
        if (mezclados[i + 1]) {
            finales.push(createMatch(mezclados[i], mezclados[i + 1]));
        }
    }
    return finales;
}

// ------------------ UTILIDADES ------------------

function createMatch(local, visitante) {
    return {
        local,
        visitante,
        golesLocal: null,
        golesVisitante: null,
        jugado: false,
        ida: true,
        vuelta: true,
        vueltaEnCasaDe: local.puntos >= visitante.puntos ? local.nombre : visitante.nombre
    };
}

function getRandomExcept(exclude, pool) {
    const options = pool.filter(p => !exclude.includes(p));
    return options[Math.floor(Math.random() * options.length)];
}

function shuffleArray(array) {
    const copia = [...array];
    for (let i = copia.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [copia[i], copia[j]] = [copia[j], copia[i]];
    }
    return copia;
}

// Simula un "ganador" para fines de estructuración de ronda 2
function winnerMock(match) {
    return match.local.puntos >= match.visitante.puntos ? match.local : match.visitante;
}

export default generatePlayoffs;
